commands.command:
upstream backend {
    server backend1.example.com;
    server backend2.example.com;
}

server {
    listen 80;

    location / {
        proxy_pass http://backend;
    }
}

const redis = require('redis');
const client = redis.createClient();

client.on('error', (err) => {
  console.log('Error ' + err);
});

vcl 4.0;
backend default {
    .host = "127.0.0.1";
    .port = "8080";
}

sub vcl_recv {
    if (req.url ~ "^/static/") {
        return (hash);
    }
}
